window.ANCHOR_SEED = {"subject":{"id":"biz-hsc","name":"Business Studies","tagline":"HSC · Finance · Marketing · Operations","dual":true,"tabs":[{"id":"tab-finance-role","name":"Finance — Role","cards":[{"id":"b001","term":"Strategic Role of Financial Management","def":"Concerned with ensuring that financial resources within a business are managed effectively and efficiently to achieve strategic and financial goals.","key":"Ensures the business has sufficient funds · Manages the allocation of resources · Supports other KBFs · Guides long-term strategic direction","group":"Strategic Role & Objectives"},{"id":"b002","term":"Profitability","def":"The financial gain a business makes from its operations after all expenses are accounted for.","key":"Improved by: increasing revenue · decreasing COGS · decreasing expenses\nBoth a short-term and long-term objective","group":"Strategic Role & Objectives"},{"id":"b003","term":"Growth","def":"The expansion of business activities and size.","key":"Internal (organic): expand product range, employees, outlets, production, market share, technology\nExternal: acquisition/takeover — backward vertical integration, forward vertical integration, horizontal integration, diversification\nLong-term objective only","group":"Strategic Role & Objectives"},{"id":"b004","term":"Efficiency","def":"The ability of a business to use resources effectively to maximise outputs, as well as the ability of the business to collect outstanding payments from customers (accounts receivable).","key":"Related to profitability — decreased costs = greater profit\nBusinesses aim to lower costs through greater output from inputs (labour, machinery)\nQuicker collection of accounts receivable = more efficient business","group":"Strategic Role & Objectives"},{"id":"b005","term":"Liquidity","def":"The ability of a business to pay its short-term debts as they fall due (within 12 months).","key":"Must have sufficient cashflow to meet financial obligations, or convert current assets to cash quickly\nCash at bank is the most liquid asset\nShort-term objective · Measured by: current ratio","group":"Strategic Role & Objectives"},{"id":"b006","term":"Solvency","def":"The ability of a business to pay its long-term debts as they fall due (more than 12 months, i.e. non-current liabilities).","key":"Gearing (leverage): proportion of debt vs equity used\nHighly geared = lots of debt = less solvent · Lowly geared = largely equity = more solvent\nFor a business to be solvent, it must first be liquid · Long-term objective","group":"Strategic Role & Objectives"},{"id":"b007","term":"Short-Term Objectives (PEGL)","key":"Profitability, Efficiency, Growth, Liquidity\nOften conflict with long-term objectives (e.g. short-term profitability vs long-term growth due to increased costs to fund growth)","group":"Short vs Long Term & Objectives"},{"id":"b008","term":"Long-Term Objectives (PEGS)","key":"Profitability, Efficiency, Growth, Solvency\nConflict example: investing in growth increases costs, reducing short-term profitability","group":"Short vs Long Term & Objectives"},{"id":"b009","term":"Finance & Operations","key":"Finance depends on Ops: production/cost targets met to ensure profit; operations to be efficient, minimise wastage, minimise costs\nOps depends on Finance: funds production (raw materials, technology); provides budgets for quality management processes","group":"Interdependence with Other KBFs"},{"id":"b00a","term":"Finance & HR","key":"Finance depends on HR: consults re redundancy payments; relies on HR prudence in training, wages, bonuses\nHR depends on Finance: funds for recruitment, training and development; budgets for remuneration","group":"Interdependence with Other KBFs"},{"id":"b00b","term":"Finance & Marketing","key":"Finance depends on Marketing: careful spending on advertising; marketing to promote/sell and generate cashflow; works with marketing on pricing; establishes sales targets\nMarketing depends on Finance: costing of products; budgets to fund marketing plan; sales data and reports","group":"Interdependence with Other KBFs"}]},{"id":"tab-finance-influences","name":"Finance — Influences","cards":[{"id":"b00c","term":"Retained Profits","def":"Profit made by the business not distributed in dividends, reinvested back into the business (also known as retained earnings).","key":"Adv: Immediate access · Does not increase debt/gearing · No interest repayments\nDisadv: Funds may be limited (depends on performance) · Takes time to accumulate · Decreased dividend payments → shareholder dissatisfaction","group":"Internal Sources of Finance"},{"id":"b00d","term":"Overdraft","def":"Where a bank allows a business to overdraw its account to an agreed limit.","key":"Adv: Immediate access to funds for short-term liquidity/cash flow issues · More flexible than bank loans · May be unsecured (generally if under $250k)\nDisadv: Relatively high interest rate (~10% avg) · Set up fees · Repayments required regardless of profitability","group":"Short-Term Debt Finance"},{"id":"b00e","term":"Commercial Bills","def":"A type of bill of exchange/business loan issued by financial institutions, given for larger amounts — usually $100k+ between 30–180 days, typically for stock purchase.","key":"Adv: Borrow significant funds · Flexible — adjust principal each rollover period · Cheaper interest rate\nDisadv: Pay interest · Establishment fees · Secured","group":"Short-Term Debt Finance"},{"id":"b00f","term":"Factoring","def":"A method of raising immediate cash by selling accounts receivable to a factoring company at a discount, generally around 90% of their value.","key":"With/without recourse: unpaid customer debts are business's/factoring company's responsibility\nAdv: Immediate access (within 48 hrs) · Saves time/costs of collecting unpaid accounts · Improves cash flow\nDisadv: Lose money on accounts receivable · Third party may impact customer relationships · With recourse responsibility","group":"Short-Term Debt Finance"},{"id":"b00g","term":"Mortgage","def":"A long-term loan secured by the borrower's property.","key":"Used for property purchases · Regular payments over period (typically 25–30 years)\nAdv: Access to significant funds · Regular, predictable payments · Interest tax deductible · Lower rates than other debt\nDisadv: Property cannot be used as further security until repaid · Default = asset confiscation · Interest paid regardless of profitability · Variable loan — rate changes","group":"Long-Term Debt Finance"},{"id":"b00h","term":"Debentures","def":"Issued by companies to private investors that carry a fixed interest rate over a specific term, secured by company assets.","key":"Adv: Access to significant funds for expansion · Interest paid to investors is tax deductible · Business determines conditions (rates, period)\nDisadv: Must comply with ASIC/APRA (must issue prospectus — reveals strategies to competitors) · Increases gearing · Must provide security","group":"Long-Term Debt Finance"},{"id":"b00i","term":"Unsecured Notes","def":"Issued by companies to private investors for a fixed, high rate of interest, not secured against assets.","key":"Adv: Assets safe · Access significant funds · Does not dilute control of existing shareholders\nDisadv: Success dependent on business reputation/creditworthiness · High interest rate · Must issue prospectus · Increases gearing","group":"Long-Term Debt Finance"},{"id":"b00j","term":"Leasing","def":"Where the owner (lessor) of an asset grants possession of that asset to a lessee for a period of time in return for regular lease payments.","key":"Adv: Managing cash flow — payments spread out · Lease repayments tax deductible · Lower establishment costs · No maintenance expenses (operating lease)\nDisadv: Public companies must reveal significant leases publicly · No ownership at lease conclusion · Penalties for early termination","group":"Long-Term Debt Finance"},{"id":"b00k","term":"Ordinary Shares","def":"Part ownership in the business that entitles a private individual to receive a proportion of profits (dividend) and potentially vote on matters at the AGM.","key":"Adv: No interest payments · Dividends are optional\nDisadv: Process expensive and longer than debt · Risk of undersubscription · Dilution of ownership\nPrivate Company (Pty Ltd): New issue only · Public Company (Ltd): New issue, rights issue, placements, share purchase plans","group":"Equity Finance"},{"id":"b00l","term":"New Issue (Primary Shares)","def":"A share that has been issued and sold on the public market for the first time.","key":"Launched on ASX through Initial Public Offering (IPO) · Accompanied by a prospectus\nAdv: Success = substantial capital · Fairly safe if underwritten · Does not increase gearing\nDisadv: Expensive and time consuming · Must issue prospectus (compromises competitive advantage) · Underwriting fee · Dilutes ownership","group":"Equity Finance"},{"id":"b00m","term":"Rights Issue","def":"The privilege granted to existing shareholders to buy new shares in the same company, proportional to their existing shareholdings.","key":"Often discounted · No shareholder approval required if capital raised ≤15% of market value\nAdv: Easier to obtain finance from familiar shareholders · Access to significant funds\nDisadv: Value of shares diluted · Shares may need to be discounted · Prospectus required (ASIC/APRA) · Risk of undersubscription","group":"Equity Finance"},{"id":"b00n","term":"Placements","def":"The allotment of shares made directly from the company to sophisticated investors (institutions, HNWIs), not to the public market.","key":"Adv: No prospectus required · No shareholder approval required · Access to large capital\nDisadv: Not favoured by shareholders — price falls in value · Share price may need to be discounted as incentive","group":"Equity Finance"},{"id":"b00o","term":"Share Purchase Plans","def":"An offer to existing shareholders, company employees and managers to buy shares in the company they work for or have invested in.","key":"Adv: Employee part-ownership = incentive to raise profitability · Prospectus not required (if ≤$15k new shares per shareholder) · Easier to obtain — shareholders already familiar\nDisadv: Business incurs brokerage costs and shares discounted · Raises lower amounts of capital vs rights issue or placements","group":"Equity Finance"},{"id":"b00p","term":"Private Equity","def":"Money invested in a private company by a private equity (PE) firm not listed on the ASX.","key":"Adv: Significant capital · PE firms offer advice and expertise\nDisadv: PE firm may request board representation · Conflict in strategic direction · Dilution of ownership","group":"Equity Finance"},{"id":"b00q","term":"Banks","def":"A financial institution that receives savings as deposits from individuals, businesses and governments and in turn makes investments and loans to borrowers.","key":"Sources of finance: commercial bills, overdraft, mortgage\nOther products: loans, credit cards, legal/tax advice, economic outlook reports","group":"Financial Institutions"},{"id":"b00r","term":"Investment Banks","def":"Financial institutions (also known as merchant banks) that assist individuals, companies or governments in raising capital.","key":"Unlike retail banks, do not take deposits · Deal mainly with large corporate clients\nSources of finance: new issue, rights issue, placements, share purchase plans, private equity\nServices: customised business loans, underwriting securities, corporate financial advice · Eg: Macquarie Bank","group":"Financial Institutions"},{"id":"b00s","term":"Finance Companies","def":"Non-bank institutions that specialise in smaller commercial finance.","key":"Do not accept deposits — raise money by borrowing from small investors (selling debentures) or wholesale funds from banks\nSources of finance: leasing · Also provide secured/unsecured loans\nAdv: Fast access · Disadv: High interest · Eg: GE Capital Australia","group":"Financial Institutions"},{"id":"b00t","term":"Superannuation Funds","def":"A collection of the legally required savings of employees.","key":"Provide funds to corporate sector through investment of superannuation contributions\nInvest in shares, property, cash etc · Sources of finance: placements\nEg: Australian Super","group":"Financial Institutions"},{"id":"b00u","term":"Life Insurance Companies","def":"A contract between the policy owner and the insuring company, where the insurer promises to pay a nominated beneficiary a sum of money when the insured person dies.","key":"Policy holder pays annual premiums → creates a reservoir of money for the company to invest\nInvest surplus funds in businesses · Examples: AXA","group":"Financial Institutions"},{"id":"b00v","term":"Unit Trusts","def":"An investment scheme that pools money from many investors who share similar financial objectives, investment strategy and risk tolerance.","key":"Funds invested by professional investment managers in a variety of financial assets (property, shares, business loans, short-term money markets)","group":"Financial Institutions"},{"id":"b00w","term":"Australian Securities Exchange (ASX)","def":"Operates as a stock exchange, providing marketplace services for the trading of shares.","key":"Sources of finance: new issue\nPrimary market: new shares issued for the first time\nSecondary market: existing shares are traded between investors","group":"Financial Institutions"},{"id":"b00x","term":"ASIC","def":"Australia's corporate, markets and financial services regulator.","key":"Independent Commonwealth body · Administers and enforces the Corporations Act 2001 (Cth)\nMain roles: maintain/facilitate/improve performance of the financial system; promote confident participation by investors/consumers; release info about companies publicly\nEffect: businesses must comply with Corporations Act and lodge financial statements with ASIC · When raising finance, ASIC provides regulatory oversight (e.g. requirement of prospectus)\nCriticism: 2018 Royal Commission — ASIC criticised for not fully utilising regulatory powers","group":"Government Influences"},{"id":"b00y","term":"Company Taxation","def":"A direct tax imposed by the Australian government on company profit.","key":"Private and public companies required to pay\nCurrent rate: >$50m turnover → 30% · ≤$50m turnover → 25% · Among world's highest\nEffects: High rate = less retained profit · Lower dividend distributions · Businesses seek legal methods to minimise tax\nAnti-avoidance: Multinational Anti-Avoidance Legislation (MAAL) · Diverted Profits Tax (DPT) — 40% tax on artificially diverted profits","group":"Government Influences"},{"id":"b00z","term":"Global Economic Outlook","def":"The expected level of economic growth in respective regions and throughout the world.","key":"Economic outlook projections create or limit business opportunities\nForecasts affect business decision making (e.g. investing into respective markets)\nPositive projection = business capitalises on consumer confidence\nCurrent issues: increasing inflation, interest rates, political instability, slowing global growth, energy/food crisis","group":"Global Market Influences"},{"id":"b010","term":"Global Availability of Funds","def":"Refers to the ease with which a business can access funds on international financial markets.","key":"Based on risk, supply of funds and economic conditions\nHigh availability = funds at lower interest rates\nLow availability in one country = businesses borrow funds overseas\nDifficult access = businesses rely on internal sources (retained profits)","group":"Global Market Influences"},{"id":"b011","term":"Global Interest Rates","def":"The cost of borrowing funds and the return received on invested funds.","key":"Business wanting domestic expansion may seek overseas funds for lower rates (savings may be limited by exchange rate fluctuations)\nLower rates → cheaper/easier access to debt → more willing to increase gearing\nInterest repayments impact profitability","group":"Global Market Influences"}]},{"id":"tab-finance-processes","name":"Finance — Processes","cards":[{"id":"b012","term":"Financial Needs","def":"How much finance a business requires to achieve its financial objectives.","key":"Determined by: size · current position in business life cycle · future plans · capacity to source finance (debt/equity)\nInformation sources: income statement, cash flow statement, balance sheet, financial ratios, market trends","group":"Planning and Implementing"},{"id":"b013","term":"Budgets","def":"Documents that provide information in quantitative terms about the requirements to achieve a particular purpose.","key":"Three types: Operating (main business activities — raw materials, expenses, labour, COGS) · Project (capital expenditure/R&D projects) · Financial (forecasted income statement, balance sheet, cash flows)\nEffects: provide a framework · assist with forecasting · allow efficient/effective allocation of financial resources","group":"Planning and Implementing"},{"id":"b014","term":"Record Systems","def":"The processes used to gather, store, record and retrieve information.","key":"Info should be accurate, reliable and accessible · Can be manual or electronic\nLarge businesses use Management Information Systems (MIS) to monitor all aspects of the budgetary process\nEffects: access data quickly and effectively · identify and analyse trends","group":"Planning and Implementing"},{"id":"b015","term":"Financial Risks","def":"The risk of being unable to cover financial obligations.","key":"Considerations: debt/equity ratio · economic conditions · interest/exchange rates · amount of debt due · liquidity/solvency\nBusinesses must take appropriate risk — ensure profit sufficient to cover debt and provide returns for shareholders\nRisk minimised by: increasing working capital and monitoring profit levels\nGreater risk → greater potential profit · Excessive risk → loan default, asset confiscation","group":"Planning and Implementing"},{"id":"b016","term":"Financial Controls","def":"The policies and procedures that ensure the objectives of the business are achieved in the most efficient way.","key":"Prevents: theft · fraud · lost/damaged assets · errors in record systems\nExamples: clear authorisation and responsibility for tasks · separation of duties · internal audits · rotation of duties · cash banked daily · security cameras · inventory checks · credit procedures","group":"Planning and Implementing"},{"id":"b017","term":"Debt Financing — Advantages & Disadvantages","key":"Adv: Lender does not gain ownership/control · Increased funds → potential increased profit · Interest payments tax deductible · Funds usually readily available · Flexible (interest rate and loan period)\nDisadv: High debt → default risk if interest rates rise · Repayments at set timeframes regardless of liquidity/profitability · Security often required · Increases gearing → adverse impact on solvency · Lenders have first claim in bankruptcy · Supply of funds can fluctuate","group":"Debt & Equity Financing"},{"id":"b018","term":"Equity Financing — Advantages & Disadvantages","key":"Adv: Does not have to be repaid · Cheaper — no interest payments · Does not increase gearing · Less risk for business and owner · Dividends not compulsory\nDisadv: Lower returns for owners · Dividends paid from profits · Dilution of ownership and possible loss of control · Longer process than debt finance · Potential for undersubscription","group":"Debt & Equity Financing"},{"id":"b019","term":"Matching the Terms and Source of Finance to Business Purpose","def":"The principle that short-term funds should be used to pay short-term debts and long-term funds should be used to purchase or fund long-term assets.","key":"Long-term assets (NCA) must be funded so that repayments match the earnings of the asset\nExample: computers funded by 2-year lease or 2-year bank loan — matching economic life of asset\nShort-term debt (e.g. commercial bills, overdraft) → fund short-term commitments (pay expenses, purchase stock)\nLong-term debt (e.g. mortgage, unsecured notes, debentures, leasing) → fund non-current assets","group":"Debt & Equity Financing"},{"id":"b01a","term":"Cash Flow Statement","def":"Shows the movement of cash receipts (inflows) and cash payments (outflows) resulting from transactions over a period of time.","key":"Analysis over time allows identification of trends\nAllows businesses to make informed spending decisions\nCategories: operating activities · investing activities · financing activities","group":"Financial Statements"},{"id":"b01b","term":"Income Statement","key":"Shows revenue, expenses and profit/loss over a period · Also called profit and loss statement\nKey elements: Sales revenue − COGS = Gross Profit · Gross Profit − Expenses = Net Profit\nUsed to calculate: gross profit ratio, net profit ratio, return on equity ratio, expense ratio","group":"Financial Statements"},{"id":"b01c","term":"Balance Sheet","key":"Shows assets, liabilities and equity at a point in time · A financial snapshot\nEquation: Assets = Liabilities + Equity\nCurrent assets: cash, receivables, inventories · Non-current assets: property, plant, equipment\nCurrent liabilities: payables, overdraft · Non-current liabilities: mortgages, debentures","group":"Financial Statements"},{"id":"b01d","term":"Current Ratio","def":"Measures a business's ability to pay its short-term debts (liquidity). Formula: Current Assets ÷ Current Liabilities.","key":"Alternative names: liquidity ratio, working capital ratio\nInterpretation: 2:1 generally healthy · 4:1 = assets not used efficiently (missed opportunities) · 0.5:1 = cannot meet short-term debts\nNote: can have high CR but not be liquid if significant cash is tied up in stock/accounts receivable\nCompare to industry average or prior year","group":"Financial Ratios"},{"id":"b01e","term":"Debt-to-Equity Ratio","def":"Measures the extent to which a firm relies on debt financing (gearing). Formula: Total Liabilities ÷ Total Equity.","key":"Alternative names: gearing ratio, solvency ratio\nInterpretation: <1:1 = more equity · 1:1 = equal · >1:1 = more debt · Generally 0.5:1–1:1 indicates sound position\nHigher ratio = higher risk = less solvent · If no debt used = may be limiting potential\nCompare to industry average or prior year","group":"Financial Ratios"},{"id":"b01f","term":"Gross Profit Ratio","def":"Measures the proportion of revenue retained after the cost of goods sold. Formula: Gross Profit ÷ Sales (expressed as %).","key":"Comment: 'For every $1 of sales, X cents represents gross profit for the business'\nLower figure: prices too low, or COGS/supplier prices too high\nStrategies to improve: cheaper suppliers · economies of scale in production · increase revenue\nCompare to industry average or prior year","group":"Financial Ratios"},{"id":"b01g","term":"Net Profit Ratio","def":"Measures the proportion of revenue retained after all expenses. Formula: Net Profit ÷ Sales (expressed as %).","key":"Comment: 'For every $1 of sales, X cents represents net profit for the business'\nGenerally accepted: 15% or industry average or prior year\nMeasures operating costs and expenses\nStrategies to improve: minimise expenses · increase revenue","group":"Financial Ratios"},{"id":"b01h","term":"Return on Equity Ratio","def":"Measures how effectively funds contributed by owners generate profit. Formula: Net Profit ÷ Total Equity (expressed as %).","key":"Comment: 'For every $1 of equity contributed by owners, they receive X cents in return'\nGenerally accepted: 10–15% or industry average or prior year\nShould be higher than return from alternative investments (e.g. bank)","group":"Financial Ratios"},{"id":"b01i","term":"Expense Ratio","def":"Measures the proportion of revenue consumed by operating expenses. Formula: Total Expenses ÷ Sales (expressed as %).","key":"Comment: 'For every $1 of sales, X cents represents expenses for the business'\nAlso: GP ratio − NP ratio = Expense ratio\nLower figure indicates better cost control and efficiency\nStrategies to improve: expense minimisation — identify specific expenses from P&L statement","group":"Financial Ratios"},{"id":"b01j","term":"Accounts Receivable Turnover Ratio","def":"Measures how efficiently a business collects outstanding debts. Formula: Sales ÷ Accounts Receivable (gives number of times collected; 365 ÷ result = number of days).","key":"Higher ratio = lower days = better (business collecting debts quickly)\nStrategies to improve: check customer credit ratings · follow up unpaid accounts · encourage cash-only payment · tighter credit policies · interest on overdue accounts","group":"Financial Ratios"},{"id":"b01k","term":"Over Different Time Periods","def":"Comparing financial ratios to previous periods of time to identify trends.","key":"Pressure for continual improvement of performance\nUseful for identifying trends (profitability, efficiency, stability)\nAllows trend identification and corrective action (e.g. marketing strategies, cheaper suppliers)","group":"Comparative Ratio Analysis"},{"id":"b01l","term":"Against Standards","key":"Comparing to internally established standards (budgeted vs actual figures)\nComparing to external standards (industry averages)","group":"Comparative Ratio Analysis"},{"id":"b01m","term":"With Similar Businesses","key":"Ensures business operates efficiently relative to peers\nValid because businesses in the same industry face the same external factors\nIf below peers → implement corrective action","group":"Comparative Ratio Analysis"},{"id":"b01n","term":"Normalised Earnings","def":"The process of removing one-off/unusual items (e.g. land sale, large fine) from financial statements to provide a more realistic representation of ongoing financial performance.","key":"Limitation: if normalisation does NOT occur, one-off items give a false impression of earnings and profit, misleading investors","group":"Limitations of Financial Reports"},{"id":"b01o","term":"Capitalising Expenses","def":"Recording an expense as an asset on the balance sheet rather than as an expense on the income statement (e.g. R&D expenses placed as an intangible asset).","key":"Limitation: understates expenses → overstates net profit AND overstates assets (business value)\nThis provides a misleading picture of business performance to investors","group":"Limitations of Financial Reports"},{"id":"b01p","term":"Valuing Assets","key":"Three limitations:\n1. Historical cost: uses original purchase price — may not reflect true current market value\n2. Depreciation rate: managers choose how fast NCAs depreciate — estimate, therefore false representation of business value\n3. Intangibles: valuing goodwill, patents, copyrights, trademarks can be subjective — may be overvalued, distorting true business value","group":"Limitations of Financial Reports"},{"id":"b01q","term":"Timing Issues","key":"Businesses may use inappropriate cut-off periods when preparing financial statements → distorts financial position\nMay shift expenses or revenue to different time periods (e.g. future expenses into current year to overstate expenses/minimise tax; current expenses into next year to maximise current profit)\nTrue representation: matching principle — revenue and costs recorded in the year they occur","group":"Limitations of Financial Reports"},{"id":"b01r","term":"Debt Repayments","key":"Financial reports may not contain specific info about debt repayments\nAbsence of info is a limitation: How long business has held the debt · When it is due · Business capacity to repay · For debts owed to business: how long debtor has owed, when due, debtor capacity to repay, provisions to recover","group":"Limitations of Financial Reports"},{"id":"b01s","term":"Notes to the Financial Statements","key":"Report details and additional info left out of main financial statements (e.g. accounting methodologies)\nLimitation: these notes contain important info that could assist investors to navigate, analyse and understand key financial statements — if not read, investors may be misled","group":"Limitations of Financial Reports"},{"id":"b01t","term":"Ethical Issues Related to Financial Reports","key":"Businesses should provide full disclosure/transparency of relevant info to stakeholders (e.g. payments to directors)\nAudit: independent check of accuracy of financial records and accounting procedures\nExternal audit: legal requirement under Corporations Act 2001 · Internal audit: ethical best practice\nInternal audit: conducted by internal auditors/management, checks practices to ensure accuracy of data","group":"Limitations of Financial Reports"}]},{"id":"tab-finance-strategies","name":"Finance — Strategies","cards":[{"id":"b01u","term":"Cash Flow Statement (Strategy)","def":"Shows the movement of cash receipts (inflows) and cash payments (outflows) resulting from transactions over a period of time.","key":"Analysis over time allows identification of trends\nAllows businesses to make informed spending decisions, lowering expenditure during times of low cash inflows","group":"Cash Flow Management"},{"id":"b01v","term":"Factoring (Cash Flow Strategy)","def":"The selling of accounts receivable for a discounted price to a finance or specialist factoring company.","key":"Improves cash flow immediately\nWith recourse: business responsible if customer doesn't pay · Without recourse: factoring company's responsibility","group":"Cash Flow Management"},{"id":"b01w","term":"Discounts for Early Payment","def":"Offering debtors a reduction in the amount owed as an incentive to pay their accounts ahead of the due date.","key":"Can also impose late payment fees to prevent overdue payments\nPos: both incentivise debtors to pay on time · improves accounts receivable turnover ratio\nNeg: late payment fees can deteriorate business–customer relationships · business does not receive full value of accounts receivable","group":"Cash Flow Management"},{"id":"b01x","term":"Distribution of Payments","def":"Organising payments to creditors to coincide with periods of cash inflows to avoid cash flow shortages.","key":"Spreads/disperses payments so they don't all fall due at once\nPos: holds off payments until due date to maximise interest on funds in account\nNeg: ineffective timing of outflows with inflows results in cash shortages","group":"Cash Flow Management"},{"id":"b01y","term":"Control of Cash (Current Assets)","key":"Problem: cash shortfalls\nSolutions: plan timing of inflows, outflows and asset purchases · build cash reserves to cover unexpected expenses · use cash flow budgets","group":"Working Capital Management"},{"id":"b01z","term":"Control of Receivables (Current Assets)","key":"Problem: slow collection of accounts receivable\nSolutions: check credit ratings of customers · follow up unpaid accounts with formal letters · tighter credit policies · interest on overdue payments\nImplication of tight credit policies: customers may choose competitors","group":"Working Capital Management"},{"id":"b020","term":"Control of Inventories (Current Assets)","key":"Problems: understocking against sales demand · overstocking (cash tied up in inventory) · perishables\nSolution: inventory control system e.g. Just in Time (JIT) — receive inventory from suppliers as needed\nJIT reduces storage costs and prevents money lying idle","group":"Working Capital Management"},{"id":"b021","term":"Control of Payables (Current Liabilities)","key":"Take advantage of early payment discounts · utilise interest-free credit periods · negotiate extended terms\n'Floor plan' finance: suppliers provide goods for period before payment is due\nConsignment finance: suppliers provide goods; payment not required until sold","group":"Working Capital Management"},{"id":"b022","term":"Control of Loans (Current Liabilities)","key":"Use short-term loans for short-term financial obligations\nCompare interest rates and terms to get the best deal\nUse bridging finance — short-term loan used until permanent finance is available\nMonitor establishment costs, interest and charges","group":"Working Capital Management"},{"id":"b023","term":"Control of Overdrafts (Current Liabilities)","key":"Avoided if possible due to high rates of interest — last resort\nOnly use for genuine short-term cash flow emergencies","group":"Working Capital Management"},{"id":"b024","term":"Leasing (Working Capital Strategy)","key":"Adv: Frees up working capital (no upfront payment) · Predictable lease payments assist with cash flow forecasting · Lease payments tax deductible\nDisadv: Asset not owned at conclusion · Obliged to make repayments for entire term · Financial lease — incur maintenance costs","group":"Working Capital Management"},{"id":"b025","term":"Sale and Lease Back","def":"A strategy where a business sells an owned asset and then leases that asset back from the buyer, freeing up working capital.","key":"Adv: Proceeds from asset sale increase working capital · Proceeds can pay off outstanding liabilities · Lease payments tax deductible\nDisadv: No longer owns the asset · Owner likely to increase lease payments over time · Obliged to make repayments for entire term","group":"Working Capital Management"},{"id":"b026","term":"Fixed Costs","def":"Costs that remain constant regardless of the level of production or goods and services sold.","key":"Examples: employee salaries, lease payments, council rates\nDifficult/nearly impossible to reduce in the short term","group":"Profitability Management"},{"id":"b027","term":"Variable Costs","def":"Costs that can change according to the level of sales or production.","key":"Examples: overtime payments, advertising, raw materials\nStrategies to cut: bulk order discounts · supplier rationalisation (reduce number of suppliers) · increasing self-service","group":"Profitability Management"},{"id":"b028","term":"Cost Centres","def":"Areas of a business where costs can be directly attributable to a particular section or department.","key":"Management provides cost centre (department) with a budget, monitors expenditure\nDirect costs: linked to a particular product/department (e.g. marketing's use of paper)\nIndirect costs: shared by more than one department (e.g. electricity)\nUsed to: identify high-cost areas and work with them to minimise costs","group":"Profitability Management"},{"id":"b029","term":"Expense Minimisation","key":"Strategies include:\nLow-cost country sourced inputs · Cut supply chain intermediaries · Lean production (minimise waste, maximise efficiency) · Volume aggregation (better deals by consolidating volumes) · Competitive bidding (suppliers bid for contract) · Specification improvement (avoid unnecessary expensive items)","group":"Profitability Management"},{"id":"b02a","term":"Revenue Controls / Marketing Objectives","key":"Sales objectives: cost-volume-profit analysis to determine break even\nSales mix: increase production of high-demand products; decrease low-demand; product deletion for underperforming products\nPricing policy: determine optimal pricing based on production cost, competitors, quality image","group":"Profitability Management"},{"id":"b02b","term":"Exchange Rates","key":"AUD appreciation: imports cheaper → inputs purchased overseas cheaper · exports more expensive for overseas buyers (bad for exporters)\nAUD depreciation: imports more expensive → raw materials from overseas cost more · exports cheaper for overseas buyers (good for exporters)\nSummary: AUD up → Exporter LOSES, Importer WINS · AUD down → Exporter WINS, Importer LOSES","group":"Global Financial Management"},{"id":"b02c","term":"Hedging","def":"A strategy used by a business to reduce the financial risk associated with exchange rate movements.","key":"Done at time of original transaction · 'Spot rate' = exchange rate on that day · Aim is to lock in that rate\nNatural hedging strategies: offshore subsidiaries · import and export contracts in same currency · marketing strategies to reduce price sensitivity of exports\nBusinesses hedge using derivatives","group":"Global Financial Management"},{"id":"b02d","term":"Derivatives","def":"The financial instruments used to facilitate the hedge.","key":"Two main types:\n1. Forward Exchange Contract: bank guarantees agreed exchange rate on agreed amount at a future point in time · Adv: Certainty · Disadv: No benefit of favourable exchange rate movement; transaction fee\n2. Option Contract: business enters agreement to purchase 'option' to buy/sell foreign currency at agreed rate at agreed future time · Adv: Only exercised if unfavourable movement, otherwise benefit from favourable movement · Disadv: Purchasing the option costs more than a forward exchange contract","group":"Global Financial Management"},{"id":"b02e","term":"Payment in Advance","def":"Occurs when the importer transfers funds to the seller/exporter's bank account before goods are shipped.","key":"Virtually no risk for exporter\nImporters highly unlikely to agree — exposes them to high risk\nUsed if credit worthiness of importer is uncertain\nNo exposure to bad debts for exporter · No intermediaries (eliminates bank fees)","group":"Global Financial Management"},{"id":"b02f","term":"Letter of Credit","def":"The buyer/importer's bank guarantees that agreed amounts will be paid as soon as goods arrive in the importer's warehouse.","key":"Seller satisfied: bank takes risk of non-payment\nBuyer satisfied: no risk of paying for goods that do not arrive\nAdv: Reduces risk for BOTH parties\nDisadv: Considerable bank fees charged","group":"Global Financial Management"},{"id":"b02g","term":"Bill of Exchange","def":"A written order by the seller/exporter requesting the buyer to pay a specified amount of money at a specified date, usually when the goods are delivered.","key":"International bank acts as intermediary · Bill of lading: agreement between exporter and transporting business (sets out where goods are sent, legal ownership)\nLegal ownership of goods only transferred to importer after payment\nImplication: Reduces risk for both, but more risky for seller — importer may still delay or not pay","group":"Global Financial Management"},{"id":"b02h","term":"Clean Payment","def":"Goods are shipped before payment is received.","key":"Length of credit period determined by seller–buyer relationship (maximum of 180 days generally acceptable)\nAdv: Only used where long track record of prompt payment and trust · Easiest and quickest method · No intermediaries or third parties · No risk for importer\nDisadv: Significant risk for exporter","group":"Global Financial Management"},{"id":"b02i","term":"Global Interest Rates (Strategy)","def":"The cost of borrowing funds/return a business receives from investing funds.","key":"Positive implications of borrowing overseas: cheaper rate · fewer restrictions · finance acquired more quickly\nNegative implications: rates can change · rate may be higher (bank regards overseas loan as more risky) · lower rates can be outweighed by unfavourable exchange rate movements","group":"Global Financial Management"}]},{"id":"tab-marketing-role","name":"Marketing — Role","cards":[{"id":"b02j","term":"Strategic Role of Marketing","def":"To maximise sales for an organisation through developing a group of strategies that design, plan, price, promote and distribute the company's goods or services in an attempt to obtain or maintain a sustainable competitive advantage over their competitors.","key":"Objectives (PIIIEE): Profit maximisation · Increasing market share · Increasing sales revenue · Increasing quality of customer service · Expansion of product range · Expansion into new geographical markets\nKey terminology: customer loyalty, brand awareness, repeat sales, competitive advantage, relationship marketing","group":"Strategic Role & Objectives"},{"id":"b02k","term":"Production Approach (1820–1920)","key":"Businesses and their products oriented on the demands of mass production rather than customer needs and wants\nAttitude: 'if we make it they will buy it'\nFocus: production efficiency, not customer needs","group":"Marketing Approaches"},{"id":"b02l","term":"Selling Approach (1920s–1960s)","key":"Increasing prevalence of high-quality mass production → increased competition → need for sales-oriented marketing\nBusinesses increased advertising\nStill neglected needs/wants of customer — produced what the business wanted, then advertised it","group":"Marketing Approaches"},{"id":"b02m","term":"Marketing Approach — Stage 1 (1960s–1980s)","key":"Focused on satisfying customer needs/wants identified through market research\nThe 'marketing concept': a philosophy stating all sections of a business are involved in satisfying customer needs/wants","group":"Marketing Approaches"},{"id":"b02n","term":"Marketing Approach — Stage 2 (1980s–Present)","key":"Builds on Stage 1 plus:\nCorporate Social Responsibility (CSR): focus on social, environmental and financial outcomes (triple bottom line)\nCustomer orientation: decisions and practices based on customer wants and interests\nRelationship marketing: development of long-term, cost-effective relationships → customer satisfaction → retention, loyalty, repeat sales","group":"Marketing Approaches"},{"id":"b02o","term":"Resource Market","def":"Businesses involved in primary production such as agriculture, forestry, fisheries and the extraction of natural resources.","key":"Examples: farming, mining, timber industry\nFirst link in the supply chain","group":"Types of Markets"},{"id":"b02p","term":"Industrial Market","def":"Businesses that purchase raw materials that are required in the production of their product — the most common example is a manufacturer.","key":"Example: Bakers Delight purchases eggs to produce bread\nBusinesses buying from businesses (B2B)","group":"Types of Markets"},{"id":"b02q","term":"Intermediate Market","def":"Businesses that purchase goods to on-sell to other businesses or consumers, such as wholesalers and retailers.","key":"Examples: wholesalers, retailers\nAct as intermediaries between producers and end consumers","group":"Types of Markets"},{"id":"b02r","term":"Consumer Market","def":"End users who purchase goods and services for their own personal use.","key":"Products designed to satisfy individual and household needs/wants\nThe final stage in the supply chain","group":"Types of Markets"},{"id":"b02s","term":"Mass Market","def":"Products with mass appeal regardless of age or income — aimed at all buyers.","key":"Example: Toothpaste\nHigh volume, often standardised product · Appeals to the broadest possible audience","group":"Types of Markets"},{"id":"b02t","term":"Niche Market","def":"A very small section of the market with a specific need for a particular good or service.","key":"Example: high-performance European cars\nLower volume, often highly specialised or premium product · Targets a very specific customer segment","group":"Types of Markets"},{"id":"b02u","term":"Marketing & Operations","key":"Marketing depends on Ops: market research identifies desired needs/wants — ops must supply product with desired features and reliably distribute it\nM and O consult on product design — affects production process\nMarketing sales predictions affect volume of units produced and resources required\nMarketing relies on Ops to produce quality products, otherwise reputation is tarnished","group":"Interdependence with Other KBFs"},{"id":"b02v","term":"Marketing & Finance","key":"Marketing relies on Finance: budgets to undertake market research and promotional strategies\nFinance relies on Marketing: market research to assist investment decisions · marketing generates sales/cashflow to fund business\nMarketing and Finance work together: determine appropriate pricing and distribution strategies","group":"Interdependence with Other KBFs"},{"id":"b02w","term":"Marketing & HR","key":"Marketing relies on HR: to source, train, develop and motivate marketing staff · to recruit marketing staff\nHR relies on Marketing: to provide appropriate role descriptions and requirements so that appropriately skilled workers can be sourced","group":"Interdependence with Other KBFs"}]},{"id":"tab-marketing-influences","name":"Marketing — Influences","cards":[{"id":"b02x","term":"Psychological Factors","def":"Psychological factors are influences within an individual that affect their buying behaviour.","key":"Five main factors (LAMPP): Learning, Attitude, Motive, Perception, Personality","group":"Psychological Factors"},{"id":"b02y","term":"Perception","key":"How an individual views a business and its products\nMarketing response: create positive perception (quality, innovative, superior) in the mind of the consumer","group":"Psychological Factors"},{"id":"b02z","term":"Motive","key":"Reason why an individual purchases a product\nMarketing response: promotion motivates customers to buy by targeting their motives (e.g. comfort, safety, taste)","group":"Psychological Factors"},{"id":"b030","term":"Attitude","key":"A person's overall feeling about a business or product\nMarketing response: negative attitude means adjustment of strategy required","group":"Psychological Factors"},{"id":"b031","term":"Personality","key":"Behaviours and characteristics that make up a person · influences types and brands purchased\nMarketing response: appeal to the personality and self-image of the target market","group":"Psychological Factors"},{"id":"b032","term":"Learning","key":"Changes in an individual's buying behaviour caused by information and experiences\nSuccessful marketing strategies improve customer awareness and encourage brand loyalty","group":"Psychological Factors"},{"id":"b033","term":"Sociocultural Factors","def":"Forces exerted by other people and groups that affect individual buying behaviour.","key":"Four main factors (CRFS): Culture/subculture, Reference group, Family, Social class","group":"Sociocultural Factors"},{"id":"b034","term":"Social Class","key":"Education, income (socioeconomic status), occupation\nInfluences type, quality and quantity of products bought\nMarketing response: target products to different social classes based on income and unique needs","group":"Sociocultural Factors"},{"id":"b035","term":"Culture and Subculture","key":"Values, beliefs and traditions of society affecting buyer behaviour · affects lifestyle and product choices\nMarketing response: market products in a way that is respectful of culture to avoid negative perception","group":"Sociocultural Factors"},{"id":"b036","term":"Family","key":"Individual's role within a family influences buying decisions (e.g. women/mothers often make food buying decisions)","group":"Sociocultural Factors"},{"id":"b037","term":"Reference (Peer) Group","key":"A group that can influence one's attitude, values and beliefs\nMarketing response: use peer influence/endorsements to drive purchasing behaviour","group":"Sociocultural Factors"},{"id":"b038","term":"Economic Factors","def":"Changes in spending and income in the wider economy that influence consumer buying behaviour.","key":"During economic growth: rising incomes · lower unemployment · consumer confidence · increased consumption · reduced price sensitivity\nDuring decline: reverse of above\nImplications: Growth = intensified promotion to increase sales and market share · Decline = review pricing strategies to maintain sales/revenue","group":"Economic & Government Factors"},{"id":"b039","term":"Government Factors","def":"Government policies can influence economic activity, thus buying behaviour, consumption patterns and the marketing plan.","key":"Fiscal policy (government spending and taxation rates): personal income tax rates influence spending habits · taxes on products impact consumption (tariffs, excise tax)\nMonetary policy (interest rates): impacts individual spending and consumption patterns re disposable income (especially mortgage holders)\nRegulatory bodies/legislation: age restrictions (alcohol, tobacco) · businesses must comply with ACL, CCA · ACCC enforces compliance","group":"Economic & Government Factors"},{"id":"b03a","term":"Consumer Law Framework","key":"Legislation: Competition and Consumer Act 2010 (Cth) — Schedule 2 is the Australian Consumer Law (ACL)\nACCC: monitors, investigates and enforces CCA/ACL · Can initiate federal court action · Fines: up to $10m/breach for businesses, $500k for individuals\nMain purposes: protect consumers against undesirable practices · regulate trade practices that restrict competition","group":"Consumer Laws"},{"id":"b03b","term":"Deceptive and Misleading Advertising","def":"Where a business makes false or misleading claims that harm or deceive the consumer.","key":"ACL: the 'dominant message' and 'overall impression' conveyed cannot be deceptive or misleading\nExamples: fine print (important conditions difficult to read) · bait and switch advertising · false country of origin claims\nImplications: ACCC investigation · federal court action · fines · damaged brand image/reputation","group":"Consumer Laws"},{"id":"b03c","term":"Price Discrimination","def":"Refers to the setting of different prices for the same product in different markets.","key":"CCA prohibits price discrimination if it could 'substantially reduce competition' (restricting market entry, forcing competitors out)\nLegal in some circumstances: accounting for transportation costs · market-specific tariffs and taxes · different markets between seller/customer and supplier/retailer\nImplications: ACCC investigation · federal court action · fines · damaged brand image","group":"Consumer Laws"},{"id":"b03d","term":"Implied Conditions","def":"The conditions of a product that are not stated but implied or conveyed at the point of sale of a product.","key":"ACL provides specific guarantees are implied in all contracts\nGuarantees for goods: merchantable quality (safe, durable, appropriate quality for price) · matches description · fit for purpose\nGuarantees for services: completed with due care and skill · fit for a particular purpose · completed in a reasonable time\nImplications: businesses must ensure promotional material and product design are compliant · must refund/replace/repair defective goods","group":"Consumer Laws"},{"id":"b03e","term":"Warranties (Consumer Law)","def":"A promise made by a business to repair or replace faulty products.","key":"Minor defect: business chooses whether to repair/replace/refund · Major defect: consumer chooses repair/replace/refund\nBusiness must offer refund if: product faulty within unreasonable timeframe · product does not match description · fails to perform intended function\nNo specific timeframe under legislation — must be 'reasonable' based on expected life, price and usage\nWarranties can be used as a marketing/promotion tool — providing assurance/confidence to customers","group":"Consumer Laws"},{"id":"b03f","term":"Truth and Accuracy","def":"Businesses should only make truthful and accurate claims regarding their products and associated promotional/marketing material.","key":"Main unethical practices: 'Untruths' due to concealed facts (omitting pertinent info) · 'Puffery' (wildly exaggerated claims no reasonable person would believe) · Vague statements (unclear and ambiguous)\nBusinesses can submit promotional material to: Advertising Standards Board (ASB) · Australian Association of National Advertising (AANA)\nEngaging in above practices → damaged brand image","group":"Ethical Issues"},{"id":"b03g","term":"Good Taste in Advertising","def":"Businesses should comply with societal norms and expectations in all forms of advertising/promotional material.","key":"Highly subjective · Generally considered objectively bad taste: over-sexualisation · discrimination · mature content displayed to children\nImportant for businesses to consider the characteristics of their target market\nAdvertising in bad taste may have 'cut through' capability but consumers do not respond well → damaged brand image","group":"Ethical Issues"},{"id":"b03h","term":"Products that May Damage Health","def":"Refers to products that may have a detrimental impact on the health or quality of life of consumers.","key":"Unethical to promote a product that damages health as if it does not have these detrimental effects\nCreating demand for harmful products is also unethical · Children often targeted due to naivety and influence on parent buying decisions\nFederal government has sought to restrict goods and services detrimental to health (e.g. alcohol)\nIn an increasingly health-conscious society, these products may be looked upon unfavourably → damaged brand reputation","group":"Ethical Issues"},{"id":"b03i","term":"Engaging in Fair Competition","def":"Refers to engaging in fair market practices that do not have a detrimental impact on restricting levels of competition within an industry.","key":"ACCC aims to promote fair and ethical behaviour\nExamples of unfair competition: Cartel conduct/price fixing (two or more businesses agree to act together to increase profits) · Misuse of market power/predatory pricing (dominant business uses industry power to damage competitors) · Exclusive dealing (forcing suppliers into exclusive arrangements) · Land banking (purchasing land/retail space to prevent competitors from accessing it)\nImplications: damaged brand reputation; ACCC enforcement","group":"Ethical Issues"},{"id":"b03j","term":"Sugging","def":"Selling under the guise of market research.","key":"Disguised marketing process using survey questions to determine interests/needs, then offering a product based on those answers\nEthical concern: individuals believe they are participating in genuine market research\nImplications: individuals may be wary of authentic market research in the future · damages brand reputation","group":"Ethical Issues"}]},{"id":"tab-marketing-processes","name":"Marketing — Processes","cards":[{"id":"b03k","term":"Situational Analysis","def":"Provides a precise understanding of a business's competitive positioning in the business environment.","key":"Uses this data to develop marketing strategies and corrective action\nTools: SWOT analysis, product life cycle analysis","group":"Situational Analysis"},{"id":"b03l","term":"SWOT Analysis","def":"Involves the identification and analysis of internal strengths and weaknesses, as well as opportunities in and threats from the external environment.","key":"Strengths (internal): product popularity, loyal customers, skilled workforce, efficient operations, solid financial position\nWeaknesses (internal): inexperienced workforce, obsolete technology, past failures\nOpportunities (external): new technologies, falling interest rates, expansion opportunities\nThreats (external): new laws/regulations, new competitors, increased competitor market share\nImplication: capitalise on strengths and opportunities; minimise weaknesses and threats","group":"Situational Analysis"},{"id":"b03m","term":"Product Life Cycle","def":"The sequence of stages a product experiences during its lifetime.","key":"Introduction: limited consumer awareness · slow sales · limited profit or loss · Strategies: intensive promotion, penetration/loss-leader pricing, indirect channels\nGrowth: rapid increase in sales · increasing market share · increasing profit · Strategies: encourage brand loyalty, promotion to wider audience, maintain/increase price, geographic expansion\nMaturity: sales level off/plateau · market saturation · profits begin to decline · Strategies: redesign packaging, new features, lower price to maintain market share\nDecline: sales decline · potential product deletion · Strategies: narrow customer focus, limited production, reduced price, discontinue promotion","group":"Situational Analysis"},{"id":"b03n","term":"Market Research","def":"The systematic process of collecting, recording and analysing information and data concerning a specific marketing issue.","key":"Yields both qualitative and quantitative data\nAllows business to develop: appropriate marketing strategies · corrective action","group":"Market Research"},{"id":"b03o","term":"Market Research Steps","key":"1. Determining information needs: accurately identify the situation or problem\n2. Data collection: Primary data (surveys, observation, experiments) · Secondary data (internal: customer feedback, sales data; external: news articles, industry reports)\n3. Data analysis and interpretation: convert raw data into useful information · statistical interpretation to determine trends/patterns and appropriate response","group":"Market Research"},{"id":"b03p","term":"Implications of Market Research","key":"Positive: allows business to better understand psychological, sociocultural, economic and government (PSEG) influences on consumer choice · allows refinement of marketing strategies to satisfy specific needs and wants\nNegative: time and cost · potential bias · unreliable data (small sample size)","group":"Market Research"},{"id":"b03q","term":"Marketing Objectives","def":"The realistic and measurable goals to be achieved through the marketing plan.","key":"Should be SMART: Specific, Measurable, Achievable, Realistic, Timely\nCommon objectives: profit maximisation · increasing market share · increasing sales revenue · increasing quality of customer service · expansion of product range · expansion into new geographical markets","group":"Market Objectives & Targeting"},{"id":"b03r","term":"Target Market","def":"The group of customers (present and potential) to which a business intends to sell its products.","key":"Approaches: Mass marketing (entire population) · Mass segmentation (dividing market into groups) · Niche market (narrowly selected target market)","group":"Market Objectives & Targeting"},{"id":"b03s","term":"Primary Target Market","def":"The segment of the target market where most marketing resources are directed.","key":"Largest and most important customer segment\nMarketing resources concentrated here for greatest impact","group":"Market Objectives & Targeting"},{"id":"b03t","term":"Secondary Target Market","def":"A smaller and less important segment of the target market.","key":"Receives fewer marketing resources than the primary target market\nStill worth pursuing as an additional revenue stream","group":"Market Objectives & Targeting"},{"id":"b03u","term":"The 7 Ps of Marketing","key":"Product: goods and/or services offered; includes branding and packaging\nPrice: pricing methods (cost, market, competition-based) and pricing strategies (skimming, penetration, loss leaders, price points)\nPromotion: advertising, personal selling, relationship marketing, sales promotions, publicity and PR\nPlace: distribution channels, channel choice (intensive, selective, exclusive), physical distribution\nPeople: quality of interaction between customer and employees\nProcesses: flow of activities in delivery of service\nPhysical Evidence: the environment in which a service is delivered","group":"Developing Marketing Strategies — Overview"},{"id":"b03v","term":"Implementation","def":"The process of putting the marketing plan and strategies into operation.","key":"Developing a financial forecast: cost and revenue projections (costs: market research, product development, promotion, distribution; revenue: sales)\nAssists to determine allocation of marketing resources","group":"Implementation, Monitoring & Controlling"},{"id":"b03w","term":"Monitoring","def":"The process of measuring actual results against planned performance.","key":"Tools: sales analysis · market share analysis · marketing profitability analysis\nMarketing profitability analysis: breaking down marketing expenses and results into specific activities to assess their effectiveness","group":"Implementation, Monitoring & Controlling"},{"id":"b03x","term":"Controlling","def":"The process of assessing objectives against predetermined standards, and taking corrective action to ensure they are achieved.","key":"Corrective action strategies: changes in the marketing mix (modifications to product, promotion, place, price) · new product developments (replace products in decline stage) · product deletion (eliminate outdated/underperforming products)","group":"Implementation, Monitoring & Controlling"}]},{"id":"tab-marketing-strategies","name":"Marketing — Strategies","cards":[{"id":"b03y","term":"Market Segmentation","def":"Involves dividing the total market into segments — groups of people who share one or more characteristics.","key":"Segmentation variables: Demographic (age, gender, race, income) · Geographic (region, urban/suburban/rural) · Psychographic (lifestyle, personality, motives) · Behavioural (purchase occasion, benefits sought, price sensitivity)\nPos: segmentation allows market research to understand buying behaviour · strategies can be refined and targeted · utilise marketing resources more efficiently\nNeg: without segmentation, business will have poor understanding of buying behaviour → inefficient use of resources","group":"Segmentation, Differentiation & Positioning"},{"id":"b03z","term":"Product/Service Differentiation","def":"The process of developing and promoting differences between the business's products or services and those of its competitors.","key":"Points of differentiation: customer service · greater convenience · more features · better quality/performance · recognition of social and ethical issues · packaging or labelling · environmentally friendly products · better value for money\nImplication: enables business to sustain long-term competitive advantage","group":"Segmentation, Differentiation & Positioning"},{"id":"b040","term":"Positioning","def":"Refers to a consumer's perception of a brand or product in relation to competing brands or products in the market.","key":"Variables contributing to positioning: name · price · quality · packaging · styling · promotion · channels of distribution\nPos: effective positioning induces sales from target audience — they believe your good best satisfies their needs → competitive advantage\nNeg: incorrect positioning leads target audience to believe a competitor is more appropriate","group":"Segmentation, Differentiation & Positioning"},{"id":"b041","term":"Goods and Services","def":"Products that can be offered in an exchange for the purpose of satisfying a need or want.","key":"Total product concept: refers to the tangible and intangible benefits a product possesses\nTangible elements: features, quality, quantity, packaging\nIntangible elements: pre-sale and after-sale service, reputation, warranty\nIf elements better meet needs/wants relative to competition → competitive advantage","group":"Product"},{"id":"b042","term":"Branding","def":"A name, term, symbol or design that identifies a product and distinguishes it from its competition.","key":"Brand name: the part of the brand that can be spoken · Logo: graphic representation that identifies a business or product · Trademark: registering a brand name or logo for exclusive rights of use\nBenefits: creates recognition and identity · positive differentiation · creates business value · promise of quality · easier to introduce new products (reduced perceived risk) · gain repeat sales (loyalty) · retailers want to stock successful brands · allows higher prices to be charged\nNegative: development of a global brand is cost and time intensive · negative experiences/publicity can damage brand reputation (difficult to change once damaged)","group":"Product"},{"id":"b043","term":"Packaging","def":"Involves the development of a container and the graphic design for a product.","key":"Aims: Identification · Containment · Protection · Safety · Attractiveness\nConsiderations: colour, size, placement of brand name, shape, texture, amount of info, graphics, labelling, government regulations\nPos: preserves product · protects from damage/tampering · attracts consumer attention · assists display · makes transport and storage easier · reinforces brand awareness\nNeg: high quality packaging expensive · inappropriate packaging → spoilage/damage/warranty claims · excessive packaging → damaged brand image due to environmental concern · bulky packaging → increased transport costs","group":"Product"},{"id":"b044","term":"Price","def":"The amount of money a customer is prepared to offer in exchange for a product.","key":"Too high = lost sales · Too low = impression of poor quality\nInfluenced by: competition · positioning · costs · economic activity · supply and demand · exchange rates and tariffs · customer loyalty · product life cycle stage\nCan: create desired positioning · drive customer buying behaviour · be a point of differentiation · be used as a promotional strategy","group":"Price"},{"id":"b045","term":"Cost-Based Pricing","def":"Involves determining the cost of production, then adding a pre-determined mark-up/profit margin to the price.","key":"Includes: direct material and labour costs + overhead costs + mark-up percentage\nPos: ensures profit on all units sold · effective for new products · straightforward to calculate\nNeg: can be difficult to determine appropriate mark-up","group":"Price"},{"id":"b046","term":"Market-Based Pricing","def":"Involves setting prices based on the interaction between supply and demand.","key":"Sets the price at whatever the market is prepared to pay · Often used for seasonal products\nPos: when supply restricted and demand high → maximise profit · capitalise on favourable market conditions\nNeg: if supply particularly high and demand low → business may need to price below cost of production","group":"Price"},{"id":"b047","term":"Competition-Based Pricing","def":"Involves setting prices comparable to those of competitors (below, equal, or above).","key":"Price leader: major business in an industry whose pricing decisions heavily influence competitors\nPricing below competitors: Pos: gain market share, attract price-conscious customers · Neg: adversely affect positioning, create perception of inferior quality\nPricing above competitors: Pos: product perceived as superior quality · Neg: unable to access price-conscious customers","group":"Price"},{"id":"b048","term":"Price Skimming","def":"Charging the highest possible price during the introduction stage of a product.","key":"Generally used for innovative products · Targets early buyers who are less price-sensitive\nPos: significant profit margins help offset R&D costs · if inelastic demand (consumers unfazed by price rises), capitalise to maximise profit · some consumers pay premium for prestige/status\nNeg: may attract competitors who undercut prices → loss of market share · most consumers not willing/able to pay premium price","group":"Price"},{"id":"b049","term":"Penetration Pricing","def":"Involves charging the lowest possible price to achieve a large market share.","key":"'Mass market pricing' · Usually used early in product life cycle\nPos: encourages new customers to trial product · can discourage new competitors from entering the market · build market share quickly\nNeg: may be perceived as poor quality · reduced profit margins in short term","group":"Price"},{"id":"b04a","term":"Loss Leaders","def":"Pricing a product below cost to attract customers to the business, where they may then purchase other full-priced goods.","key":"Strategy: use one product as a 'bait' to drive foot traffic and broader sales\nPos: attracts large volume of customers · increases sales of other products\nNeg: selling below cost is directly unprofitable on the loss leader item · must be carefully managed to ensure overall profitability","group":"Price"},{"id":"b04b","term":"Price Points","def":"Setting prices at psychologically significant levels that appear more attractive to consumers (e.g. $9.99 instead of $10.00).","key":"Exploits consumer psychology — consumers perceive $9.99 as significantly cheaper than $10.00\nPos: can increase sales volume without significantly reducing revenue\nNeg: consumers increasingly aware of this strategy","group":"Price"},{"id":"b04c","term":"Advertising","def":"A paid, non-personal message communicated through a mass medium.","key":"Aims to inform, remind and persuade\n6 types: mass marketing (TV, radio), direct marketing (catalogues), telemarketing, e-marketing, social media advertising, billboards\nPos: opportunity to reach an extremely large audience or a small, distinct target market · can highlight unique/quality features\nNeg: cost-intensive · relatively impersonal · consumers increasingly immune to advertising","group":"Promotion"},{"id":"b04d","term":"Personal Selling","def":"Involves the activities of a sales representative directed to a customer in an attempt to make a sale.","key":"Especially used by businesses with a complex product\nAdv: message can be modified to specific customer needs · can create long-term relationships/brand loyalty · real-life demonstrations more convincing · questions, feedback and complaints handled immediately\nDisadv: expensive (wages, commissions) · some customers reluctant to listen · effectiveness highly dependent on skills of sales consultant · time consuming","group":"Promotion"},{"id":"b04e","term":"Relationship Marketing","def":"The development of long-term, cost-effective and strong relationships with individual customers.","key":"Customer Relationship Management (CRM): focuses on catering to unique needs and wants of individuals\nHighly successful example: loyalty programs\nPos: CRM/loyalty programs → customer loyalty, retention, repeat sales · CRM tracks consumer data/patterns to further exploit sales · promotes positive word of mouth\nNeg: some markets saturated with loyalty programs · providing free item increases costs · focus on LT relationships may diminish focus on acquiring additional customers","group":"Promotion"},{"id":"b04f","term":"Sales Promotions","def":"The use of activities or materials as direct inducements to customers.","key":"Examples: coupons · premiums (gift offered to customer in return for using product) · refunds · samples · point-of-purchase displays\nPos: entice new customers · encourage trial purchase of new product (build market share) · repeat purchases · create urgency in spending decisions\nNeg: increase costs · consumers may only purchase products when discounted","group":"Promotion"},{"id":"b04g","term":"Publicity","def":"Any free news story about a business's products.","key":"Differs from advertising: it is free and not controlled by the business\nExamples: news, blogs, reviews, social media posts\nPositive publicity: enhances brand image · raises awareness · highlights favourable features\nNegative publicity: damages brand image/reputation · accuracy concerns","group":"Promotion"},{"id":"b04h","term":"Public Relations","def":"Activities aimed at creating favourable relations between a business and its customers/the public.","key":"Activities: press releases · publicising CSR initiatives · donations or charity · sponsorship of a public event\nPos: create positive brand image · reinforce favourable attitudes · effectively convey/communicate messages · crisis management: protect against unfavourable publicity\nNeg: no guarantee it will be well received or effective","group":"Promotion"},{"id":"b04i","term":"Opinion Leaders","def":"An individual who has influence over a large group of consumers.","key":"Examples: business leaders · social media influencers · celebrities\nPos: can increase trustworthiness of communication · celebrity/SMI endorsement powerful marketing tool — large following, instant engagement\nNeg: brand aligned with ambassador's (potentially tarnished) reputation · expensive","group":"Promotion"},{"id":"b04j","term":"Word of Mouth","def":"Refers to the influence on buying behaviour from conversation — e.g. friend recommendations, social media posts, online reviews.","key":"Methods: phone conversations, text messages, message boards, emails, blog posts, social media posts, online reviews\nPos: more trustworthy/effective (consumers trust reference groups more than advertisers) · inexpensive — free promotion\nNeg: difficult for business to control · negative image can spread quickly","group":"Promotion"},{"id":"b04k","term":"Place/Distribution","def":"The activities/routes taken to get the product from the factory to the customer.","key":"Efficiency is a key criteria · Interdependence with operations management\nChannels include: direct and indirect distribution routes","group":"Place / Distribution"},{"id":"b04l","term":"Direct Distribution","def":"Involves the producer sending the finished product directly to the consumer without intermediaries.","key":"Adv: no intermediaries — eliminate costs · absolute control over distribution (price, messaging, promotion) · usually faster · develop better customer relationships (relationship marketing)\nDisadv: can be cost-intensive · requires appropriate distribution facilities · may not be appropriate for high-volume products","group":"Place / Distribution"},{"id":"b04m","term":"Indirect Distribution","def":"The use of intermediaries (retailer, wholesaler, agent) to deliver the finished product from the producer to the consumer.","key":"Common channels: Producer → Retailer → Consumer · Producer → Wholesaler → Retailer → Consumer · Producer → Agent → Wholesaler → Retailer → Consumer\nAdv: more efficient if intermediaries specialise · access to retailers' existing customers, employees, foreign subsidiaries · allows focus on core functions\nDisadv: operations of intermediaries can impact business image · managing complex web is costly/time consuming · quality depends on intermediaries · intermediaries have control over pricing","group":"Place / Distribution"},{"id":"b04n","term":"Intensive Distribution","def":"Involves a business saturating the market with its product, using all possible retailers.","key":"Used for generic, low-value, convenience goods\nAdv: mass market coverage\nDisadv: expensive to manage across all outlets · potentially inefficient","group":"Place / Distribution"},{"id":"b04o","term":"Selective Distribution","def":"Involves using only a moderate proportion of all possible outlets.","key":"Selected retailers sell the product · Often used in clothing, furniture, electrical appliances\nCustomers prepared to seek out a specific retailer · Eg: Apple stores\nBalances market coverage with exclusivity","group":"Place / Distribution"},{"id":"b04p","term":"Exclusive Distribution","def":"The use of only one or limited retail outlets for a product in a large geographical area.","key":"Commonly used for exclusive, expensive products\nAdv: can reduce logistics/transportation costs · denotes image of status/luxury — creates perception of quality and exclusivity\nDisadv: limited access to consumers","group":"Place / Distribution"},{"id":"b04q","term":"Physical Distribution Issues — Transport","key":"Physical method of moving goods from one geographic location to another\nMethod determined by type of product and level of service the business wishes to provide\nMost common methods: rail, road, sea, air","group":"Place / Distribution"},{"id":"b04r","term":"Physical Distribution Issues — Warehousing","key":"Set of activities involved in receiving, storing and dispatching goods\nA warehouse acts as a central organising point for the efficient delivery of products","group":"Place / Distribution"},{"id":"b04s","term":"Physical Distribution Issues — Inventory","key":"The amount of stock a business has on hand ready for sale\nInventory control systems needed to avoid too little or too much stock\nOut of stock repeatedly: lost sales and market share · Carry too much stock: high storage costs","group":"Place / Distribution"},{"id":"b04t","term":"People","def":"The quality of interaction between the customer and employees who deliver the service.","key":"Particularly relevant for service businesses\nInvolves: recruiting and training staff\nCustomers judge business heavily on how employees treat them: handling issues/complaints, speaking to customers\nPos: appropriately trained staff → positive learned experiences → sales and loyalty\nNeg: poorly trained staff → adverse interactions → damaged reputation → negative word of mouth","group":"People, Processes & Physical Evidence"},{"id":"b04u","term":"Processes (Marketing Mix)","def":"The flow of activities involved in the delivery of a service.","key":"Need to be customer-oriented and efficient\nCustomers sensitive to processes that appear illogical, cause delays, or where messaging is inaccurate\nNeg: inefficient processes → poor customer experience → negative word of mouth\nPos: efficient processes → customer satisfaction → loyalty → competitive advantage","group":"People, Processes & Physical Evidence"},{"id":"b04v","term":"Physical Evidence","def":"The environment in which a service is delivered.","key":"Includes: location, signage, business uniforms, brochures, business cards, logo, interior design, website\nPhysical presence should match positioning\nPos: high quality indicates good impression/inviting atmosphere · influences customer perception and opinion\nNeg: can be costly · physical evidence not aligned with positioning creates mixed messages","group":"People, Processes & Physical Evidence"},{"id":"b04w","term":"E-Marketing","def":"Using the internet to perform marketing activities.","key":"Methods: web pages, SMS, blogs, social media advertising (SMA), email marketing\nOverall adv: cost-effective · access to global markets · increase business exposure · convenience for customers\nDisadv: gain visible criticism · must be continually updated · privacy concerns (SMS) · negative comments in public forums","group":"E-Marketing"},{"id":"b04x","term":"Global Branding","def":"The use of a worldwide name, symbol, logo or design that identifies a product and distinguishes it from competing products.","key":"Adv: cost-effective (same advertisement used in multiple countries) · uniform worldwide brand image · global recognition — easier to enter new markets · brand dominance — many global retailers want to stock products\nDisadv: development is cost and time intensive · difficult to align global brand with local culture/preferences","group":"Global Marketing"},{"id":"b04y","term":"Standardisation","def":"Using very similar product strategies in all markets, based on the assumption that customer needs and wants are the same.","key":"Adv: easier to manage · promotions and product design are the same → cost effective · less R&D needed · maintain positive perceptions/trust · economies of scale in production · success in one market leads to growth in demand in others\nDisadv: cannot meet market-specific needs/wants · susceptible to domestic competitors who better understand local culture and socioeconomic factors","group":"Global Marketing"},{"id":"b04z","term":"Customisation (Global Marketing)","def":"Using different product strategies for separate markets to satisfy different needs and wants.","key":"Adv: meet specific social/economic needs · more customer-oriented approach → customer satisfaction · differentiate from competitors · respond to market-specific trends\nDisadv: more expensive (different product design, production and promotion strategies) · extensive market research needed — time and cost","group":"Global Marketing"},{"id":"b050","term":"Global Pricing","def":"How a business coordinates pricing policies across different countries.","key":"Influenced by: competitive influences · socioeconomic status of customers · government regulations · exchange rates · transport costs\n3 key strategies:\n1. Customised pricing (different prices in different countries — often to cover export costs)\n2. Market customised pricing (different prices based on local market conditions and competition)\n3. Standardised worldwide pricing (same price globally — risks: domestic competitors offering lower prices, exchange rate fluctuations)","group":"Global Marketing"},{"id":"b051","term":"Competitive Positioning (Global)","def":"Refers to how a business differentiates its product from competitors in global markets.","key":"To develop/maintain sustainable competitive advantage, a global business must understand the dynamic environments in different countries\nDevelop superior competitive positioning by building and marketing high-quality relationships with customers and suppliers relative to competitors\nAchieved through: high-quality products · affordable pricing\nResult: strong brand awareness · customer loyalty","group":"Global Marketing"}]},{"id":"tab-operations-role","name":"Operations — Role","cards":[{"id":"b052","term":"Strategic Role of Operations Management","def":"A long-term approach to managing the operations process in a way that contributes to the achievement of the goals and strategic direction of the business.","key":"Performance objectives (QSDFCC): Quality, Speed, Dependability, Flexibility, Customisation, Cost\nKey terminology: reducing lead times · minimising wastage/lean production · reducing bottlenecks · cost minimisation · minimising errors/defects · achieving cost leadership","group":"Strategic Role"},{"id":"b053","term":"Cost Leadership","def":"Refers to striving to be the lowest-cost producer and the most price-competitive business in the marketplace.","key":"Costs include: inputs · labour · processing · inventory · quality management\nAchieved through: standardised goods/services · economies of scale in production · becoming more efficient · innovative/cost-efficient production methods · global sourcing of low-cost inputs · low-cost distribution methods\nPos: minimise costs · price competitive product\nNeg: may need to sacrifice product quality · may need to reduce customisable elements","group":"Strategic Role"},{"id":"b054","term":"Good/Service Differentiation (Operations)","def":"Modifying the product offered by the business so that they are unique and distinct from those offered by competitors in the marketplace.","key":"Goods differentiated by: features · quality · augmented features · unique design/technology · level of customisation\nServices differentiated by: time · level of expertise · qualifications and experience of provider · level of customisation\nCross branding/strategic alliances: another point of differentiation (e.g. Woolworths and Caltex)\nPos: enhanced business competitiveness · long-term competitive advantage · achievement of operational objectives\nNeg: differentiation = increased costs","group":"Strategic Role"},{"id":"b055","term":"Standardised Goods","key":"Uniform in quality · mass-produced · produced for the mass market\nAssist in achieving objectives: cost, quality, speed\nObjective NOT achieved: customisation","group":"Goods and Services in Different Industries"},{"id":"b056","term":"Customised Goods","key":"Vary according to the needs of individual customers\nObjectives achieved: customisation\nObjectives NOT achieved: speed, cost","group":"Goods and Services in Different Industries"},{"id":"b057","term":"Perishable Goods","key":"Short lead times required · distribution needs to be quick\nSpoilage, storage and quality are important issues","group":"Goods and Services in Different Industries"},{"id":"b058","term":"Non-Perishable Goods","key":"Longer lead times appropriate\nLess urgency in distribution","group":"Goods and Services in Different Industries"},{"id":"b059","term":"Services","key":"Intangible · exist only while being performed · generally customised · production and consumption are simultaneous","group":"Goods and Services in Different Industries"},{"id":"b05a","term":"Operations & Marketing","key":"M relies on O: market research identifies desired features → Ops must supply the product reliably\nM and O consult on product design — affects production process\nMarketing sales predictions → affect volume of units produced and resources required\nMarketing relies on Ops to produce quality products — otherwise reputation tarnished","group":"Interdependence with Other KBFs"},{"id":"b05b","term":"Operations & Finance","key":"Finance creates budgets for: inputs, equipment, new product design/development, production costs, quality management processes\nFinance monitors Ops performance → can result in changes (e.g. reduced production cost through cheaper inputs)\nFinance relies on Ops to create quality products\nFinance works with Ops to achieve 'cost leadership'","group":"Interdependence with Other KBFs"},{"id":"b05c","term":"Operations & HR","key":"Ops relies on HR to source team members with skill/experience\nHR relies on Ops to provide comprehensive job descriptions/specifications to source appropriate staff\nHR facilitates training and development of Ops staff\nHR uses rewards to motivate and improve productivity of Ops staff","group":"Interdependence with Other KBFs"}]},{"id":"tab-operations-influences","name":"Operations — Influences","cards":[{"id":"b05d","term":"Globalisation","def":"The removal of trade barriers between countries and greater transfer of capital, labour and resources.","key":"Global sourcing of inputs: Adv: lower cost · greater volume · higher quality · unique inputs · Disadv: unfavourable exchange rates · quality concerns · transportation delays\nGlobal supply chain (global web): Adv: access suppliers in different geo locations · flexibility if one supplier has delays · Disadv: logistical complexity · reliability of suppliers\nRelocation of manufacturing: Adv: lower labour costs · reduced compliance costs · skilled workforce · proximity to materials/customers · Disadv: negative publicity if domestic jobs lost\nGlobal outsourcing: Adv: efficiency gains · cost savings · increased process capability · Disadv: quality concerns · communication/language barriers · social/ethical actions of global contractor reflect on brand","group":"Globalisation"},{"id":"b05e","term":"Technology (Operations Influence)","def":"The application of science or knowledge that enables people to do new things or perform established tasks in new and better ways.","key":"Manufacturing/production technology: robotics · CAD (computer-aided design) · AI\nService technology: software · laptops · applications\nCan be used in: inventory management · manufacturing · quality management · supply chain management\nAdv: develop innovative products · decreased long-term costs (capital–labour substitution) · increased quality/precision · increased productivity · better customisation\nDisadv: high initial cost · staff retraining · require ongoing maintenance","group":"Technology, Quality & Cost"},{"id":"b05f","term":"Quality Expectations","def":"The expectations of customers in relation to the quality, durability and benefits of a good or service.","key":"Increasing QE may require: higher quality inputs · more advanced technology · enhanced quality control procedures · staff training and development\nCriteria for goods: quality of design · fitness for purpose · durability\nCriteria for services: reliability · level of customisation · professionalism\nIf expectations met: customer satisfaction · fewer complaints · reduced defects (reduced warranty claims and repair costs) · positive word of mouth\nIf not met: increased costs (warranty claims) · decreased speed (processes take longer)","group":"Technology, Quality & Cost"},{"id":"b05g","term":"Cost-Based Competition","def":"An increase in competition in the market based on cost, which has arisen as a result of globalisation.","key":"Lower costs = lower prices = pressure on other businesses\nCost reduction strategies: standardised products · economies of scale · cheaper suppliers · minimise waste · minimise fixed and variable costs\nPos: decreased costs · technology can improve efficiency and quality · competitive advantage\nNeg: decreased costs may impact quality · larger businesses more capable of economies of scale (disadvantages small businesses)","group":"Technology, Quality & Cost"},{"id":"b05h","term":"Government Policies","def":"Announced intentions and political decisions that affect business decision-making within an operations management context.","key":"Examples: Australian Industry Participation (AIP) Policy and Buy Australian Plan (pressure to source locally) · National EV Strategy and Rewiring the Nation Policy (influence energy procurement) · Modern Manufacturing Initiative (MMI) — grants for advanced manufacturing technology · Climate Active Program (encourages carbon measurement, reduction and offsetting)\nPos: government support may provide competitive advantage\nNeg: compliance costs · difficulty keeping up with changing policies","group":"Government & Legal"},{"id":"b05i","term":"Legal Regulation","def":"Laws that have been passed by the government that a business must comply with.","key":"Key legislation: Work Health and Safety Act 2011 (NSW) · Environmental and Biodiversity Conservation Act 1999 (hazardous waste management) · Competition and Consumer Act 2010 (Cth) (goods compliant with environmental and safety standards) · Food Act 2003 (NSW)\nImplications: required to conduct safe, legal operational processes · may incur compliance costs · may incur fines for non-compliance","group":"Government & Legal"},{"id":"b05j","term":"Environmental Sustainability","def":"Ensuring that current resources and development do not impact the ability of future generations to meet their needs.","key":"Businesses can minimise environmental impact by: minimising pollution/waste in production · using lower-energy processes · recycling materials · using renewable resources\nPos: improved brand image · satisfy stakeholders (community, society, environment)\nNeg: may increase costs (adjusting processes, new inputs, staff training)","group":"Environmental Sustainability & CSR"},{"id":"b05k","term":"Corporate Social Responsibility (CSR)","def":"Open and accountable business actions that are ethical and demonstrate respect to society and the environment.","key":"Includes: social responsibility · environmental responsibility\n'Triple bottom line': financial, social and environmental outcomes\nCSR measured through ISO 26000: accountability · transparency · ethical behaviour · respect for stakeholder interests · respect for the law · respect for human rights\nPos: increased employee interest/staff retention · increased customer loyalty and brand image · increased brand value\nNeg: financially burdening · unfavourable in the short term","group":"Environmental Sustainability & CSR"},{"id":"b05l","term":"Legal Compliance vs Ethical Responsibility","key":"Legal compliance: standards of behaviour that MUST be met · results in compliance costs · penalties if not met\nEthical responsibility: going BEYOND legal regulations and focusing on social and environmental outcomes too · costs beyond compliance · demonstrates business values more than just profit · acts in the 'spirit of the law'","group":"Environmental Sustainability & CSR"}]},{"id":"tab-operations-processes","name":"Operations — Processes","cards":[{"id":"b05m","term":"Inputs","def":"The resources used in the transformation (production) process.","key":"Two types: Transforming resources (carry out the transformation) and Transformed resources (are changed in the transformation)","group":"Inputs — Transforming Resources"},{"id":"b05n","term":"Transforming Resources","def":"Inputs that carry out the transformation process — they enable the change and value-adding to occur.","key":"Two types: Human resources and Facilities","group":"Inputs — Transforming Resources"},{"id":"b05o","term":"Human Resources (Operations)","def":"Individuals who provide labour to a business in exchange for income.","key":"Employees apply skills/knowledge/capabilities to materials to convert them into goods/services\nNeed to be trained and motivated (improved efficiency/productivity/speed)\nPos: well-trained and motivated employees positively influence productivity, efficiency, speed and value-adding\nNeg: training and motivational techniques can be costly","group":"Inputs — Transforming Resources"},{"id":"b05p","term":"Facilities","def":"The plant (factory or office) and machinery used in the operations processes.","key":"Machinery and equipment used to change the shape and features of materials\nMajor decisions: design layout of facilities · number of facilities · location · capacity\nPos: effective plant/process layout can improve efficiency, speed and productivity","group":"Inputs — Transforming Resources"},{"id":"b05q","term":"Transformed Resources","def":"Inputs that are changed or converted in the transformation process.","key":"Three types: Materials, Information, Customers","group":"Inputs — Transformed Resources"},{"id":"b05r","term":"Materials","def":"The basic elements used in the production process.","key":"Two types: raw materials and intermediate goods (finished product by one business, used as input by another)\nAvailability and cost of materials influence operational processes\nPos: high quality materials improve product quality · less wastage due to durability\nNeg: higher quality materials = higher costs · materials difficult to source = increased lead times","group":"Inputs — Transformed Resources"},{"id":"b05s","term":"Information (Operations)","def":"The knowledge gained from investigation, research and instruction.","key":"Services context: information provided by consumers as input (e.g. doctor, financial planner, accountant) → transformed into output (e.g. advice)\nGoods context: information on how to produce effectively/efficiently (e.g. CPA, designs, plans)\nInternal info (past sales data) and external info (market research) processed to create production schedules and improve designs\nNeg: incorrect information → poor decisions and various ramifications","group":"Inputs — Transformed Resources"},{"id":"b05t","term":"Customers (Operations)","def":"Individuals who purchase goods/services from a business to satisfy their needs and wants.","key":"Customers as an input are transformed in some way (e.g. a customer getting their hair cut is transformed)\nPreferences, desires, tastes and feedback shape marketing (and subsequently operations) decisions","group":"Inputs — Transformed Resources"},{"id":"b05u","term":"Volume","def":"The actual number of products or services produced by the operation.","key":"Mass production = high volume with high degree of process repetition\nVolume flexibility = how quickly the transformation process responds to increases/decreases in demand\nHigh volume → economies of scale/low cost per unit (equipment automation, bulk buying discounts)\nLow volume → lots of stoppages/adjustments, higher cost per unit\nOverproduction → wastage and increased inventory costs · Underproduction → lost sales\nPLC stage influences volume: establishment phase = lower volumes; growth phase = higher volumes","group":"Transformation Processes — The 4 Vs"},{"id":"b05v","term":"Variety","def":"The number of different models and variations offered in the products or services.","key":"If business has customers with different needs → goods/services modified or wide variety provided\nLow-variety operations → high-volume standardised product with low cost\nGoods tend to lower variety; services tend to higher variety\nHigh variety requires flexibility in machinery and access to inputs\nLow variety → greater speed, efficiency and cost savings\nHigh variety → complex production processes, higher costs, impacts speed and cost objectives, smaller production runs, more equipment washouts, more complex inputs to purchase and store","group":"Transformation Processes — The 4 Vs"},{"id":"b05w","term":"Variation in Demand","def":"The ability of a business to adjust its production levels in response to changes in demand.","key":"Operations must have the ability to adjust: input requirements from suppliers · labour requirements · equipment/machinery capacity · energy requirements\nNeed to forecast changes in demand and have flexible processes\nSpike in demand: suppliers may not respond fast enough → lost sales · business may not access additional labour → lost sales · machinery may not cope\nIf business has operational resources in place to cope with unexpected increases → significant increase in sales revenue (profitability)\nHigh variation → increased production costs and complexity","group":"Transformation Processes — The 4 Vs"},{"id":"b05x","term":"Visibility (Customer Contact)","def":"The degree to which customers can see the operations in action.","key":"Service-based businesses → high visibility\nManufacturing-based businesses → customers rarely see the operations process\nHighly visible operations → quality of labour is significant → need well-trained, highly skilled, adaptable staff\nCustomer contact: direct (surveys, interviews, warranty claims, verbal contact) · indirect (sales and market share data, observation)","group":"Transformation Processes — The 4 Vs"},{"id":"b05y","term":"Sequencing","def":"The order of operations processes.","key":"Assists with planning, organisation and implementation of operational processes\nMust be determined before scheduling","group":"Sequencing & Scheduling"},{"id":"b05z","term":"Scheduling","def":"The timing of operations processes.","key":"Determines when each task will be performed within the sequence\nTools used: Gantt charts and critical path analysis","group":"Sequencing & Scheduling"},{"id":"b060","term":"Gantt Chart","def":"A horizontal bar chart that shows both scheduled and completed activities over a period of time.","key":"Shows: activities that need to be performed · the order they should be completed · expected time · where activities can overlap · where activities are dependent on each other · start and end date\nPos: monitoring tool — ensures actual status of project matches planned status\nNeg: does not necessarily show relationship and interdependence between activities · does not show the most efficient way to complete a project","group":"Sequencing & Scheduling"},{"id":"b061","term":"Critical Path Analysis (CPA)","def":"Shows what activities need to be performed, the order they need to be completed in, and the time each activity will take.","key":"Purpose: determine the shortest time to complete all activities\nEach activity must be completed · some activities can be completed simultaneously\nIMPORTANT: the critical path is the path that takes the LONGEST — this is the shortest possible time to complete the project\nPos: see what tasks can be done simultaneously (speed and cost objective) · minimise bottlenecks\nNeg: delay to a task on the critical path → adverse cost and customer satisfaction · based on dependencies: availability of labour, lead times for raw materials, seasonal factors","group":"Sequencing & Scheduling"},{"id":"b062","term":"Task Design","def":"The determination of the tasks that need to be performed, how they will be performed, and the labour needs to perform the required tasks.","key":"3 steps: 1. Determine what tasks need to be performed · 2. Determine how the tasks will be performed (steps) · 3. Determine labour needs/requirements (skills audit, job analysis; if skills insufficient → recruitment)\nPos: easier for employees to successfully perform tasks in a productive manner · appropriately skilled labour ensures quality\nNeg: can take time to engage in task design, conduct a skills audit, source appropriate candidates","group":"Technology, Task Design & Process Layout"},{"id":"b063","term":"Process Layout","def":"The physical arrangement of equipment, processes and people within the operations of the business.","key":"4 types:\n1. Process/Functional layout: machinery grouped by function · high variety, low volume\n2. Product layout (assembly line): machinery arranged by sequence of tasks · uniform quality, high-volume, efficient flow\n3. Fixed position layout (project production): products remain in one location; employees/machinery/materials brought to the product · used for heavy/immobile products\n4. Office/service layout: desks/workstations grouped by similar functions · communication and collective thinking\nPos: layout choice should maximise efficiency and productivity → decreased costs, increased speed\nNeg: time/cost to organise · initial costs in structural reorganisation = large capital outlay","group":"Technology, Task Design & Process Layout"},{"id":"b064","term":"Monitoring (Operations)","def":"Measuring actual performance against planned performance.","key":"Can monitor through: statistical data analysis · customer feedback\nMonitor KPIs and SLAs such as: ops costs · lead times · inventory turnover rates · warranty claims · quality of inputs and outputs\nPos: pinpoints inefficiencies through KPIs as a benchmark · focuses attention on actions with most effective impact on overall performance","group":"Monitoring, Control & Improvement"},{"id":"b065","term":"Control (Operations)","def":"Assessing KPIs against predetermined targets and taking corrective action.","key":"Modifications/improvements to operational processes e.g.: redesign of facility layout · new technology · hiring specialist staff · source better inputs · use CPA/Gantt charts to address efficiency issues\nPos: corrective action allows business to improve operational processes · ensures business is on track to achieve performance and financial objectives\nNeg: corrective action can be costly and time consuming","group":"Monitoring, Control & Improvement"},{"id":"b066","term":"Improvement (Operations)","def":"The systematic processes, strategies and business culture used to improve product quality, efficiency and achieve key performance objectives.","key":"Possible areas of improvement: reduction of waste · inefficiencies · process flows · time · quality · cost · bottlenecks\nImprovement strategies: commitment to continuous improvement · Six Sigma approach (management techniques to reduce errors/defects — 5 steps: define, measure, analyse, improve, control)\nPos: reduces/eliminates operational problems · reduces operational costs · maximises achievement of performance objectives\nNeg: investment in continuous improvement involves both cost and time","group":"Monitoring, Control & Improvement"},{"id":"b067","term":"Outputs","def":"The good or service that is provided or delivered to the customer.","key":"The result of the transformation process · Can be measured against performance objectives (quality, speed, dependability, flexibility, customisation, cost)","group":"Outputs"},{"id":"b068","term":"Customer Service (Operations Output)","def":"Refers to how well a business meets and exceeds the expectations of customers.","key":"A high number of defects, customer complaints and long waiting times indicate improvement is needed\nOccurs before, during and after a sale\nStrategies to improve: complaints department · customer service training · minimise defects · reduce waiting times\nHigh quality customer service → customer satisfaction · loyalty · repeat sales · assists relationship marketing · long-term competitive advantage\nNeg: complaints department costly · training to up-skill employees costly and time consuming","group":"Outputs"},{"id":"b069","term":"Warranties (Operations Output)","def":"A promise made by a business to repair or replace faulty products.","key":"Ensure products are fit for purpose, durable, defect-free and of merchantable quality\nHelp with monitoring and controlling quality management\nAct as an indicator of quality management\nPos: build trust in a brand/confidence in a product — induce a sale\nNeg: poor quality → repair/replace/refund (RRR) — increased costs · poor quality products will have negative ramifications on reputation","group":"Outputs"}]},{"id":"tab-operations-strategies","name":"Operations — Strategies","cards":[{"id":"b06a","term":"Quality","def":"The ability of a business to satisfy or surpass the standards and expectations of consumers.","key":"Enhanced through: quality of design · quality of conformance · quality of service\nLevel of quality measured by: warranty claims · defect rates\nCriteria for effectiveness: units failing quality tests reduced · defects decreased · warranty claims decreased\nHigh quality → less defects · less warranty claims · improved reliability and dependability · improved customer satisfaction\nLimited commitment to quality → opposite outcomes","group":"Performance Objectives"},{"id":"b06b","term":"Speed","def":"The time it takes for operational processes to respond to changes in demand and adjust output volumes — how quick the process is.","key":"Speed goals: reduce wait times · shorter lead times · faster processing time\nAchieved by: eliminate bottlenecks · effective internal communication · maximising efficiency · flexibility\nPos: reduced wait times and shorter lead times → customer satisfaction\nNeg: efficient machinery must be purchased → costs · ops processes rushed to achieve speed may impact quality","group":"Performance Objectives"},{"id":"b06c","term":"Dependability","def":"The consistency, reliability and durability of a product.","key":"Measurement: Goods — customer complaints, warranty claims, defects · Services — customer complaints\nPos: dependable products → enhanced brand image · customer satisfaction · long-term sustainable competitive advantage\nNeg: inconsistent/unreliable → opposite · requires greater levels of quality control → increased costs · durable materials = more costly","group":"Performance Objectives"},{"id":"b06d","term":"Flexibility","def":"How quickly operational processes can adjust to changes in the market.","key":"Methods to increase flexibility (manufacturing): flexible technology · alter product design\nMethods to increase flexibility (service): increase number of service providers · increase skill level of service providers · increase technology use · increase storage capacity\nPos: changing consumer needs can be fulfilled · avoids under/over production → increased efficiency, customer satisfaction and long-term competitive advantage\nNeg: may necessitate purchase of new technology/machinery → significant capital outlay","group":"Performance Objectives"},{"id":"b06e","term":"Customisation","def":"The development of individual products to meet the specific needs of customers.","key":"Could include variations in colour, size and quality · mass customisation\nPos: maximising customer satisfaction/repeat sales · increased market share · long-term sustainable competitive advantage\nNeg: increased complexity in operational and transformation processes · generally increases lead times · may lack adequate knowledge, machinery, systems and processes","group":"Performance Objectives"},{"id":"b06f","term":"Cost","def":"Minimising operational expenses.","key":"Operational costs that can be minimised: input costs · logistics costs · inventory costs\nMinimisation strategies: volume purchasing · sourcing cheaper inputs (e.g. overseas) · waste minimisation\nPos: lower operational costs → reduced COGS and expenses → high gross and net profit · achieve cost leadership · enable lower prices → increased sales and market share\nNeg: must find a balance between cost and quality","group":"Performance Objectives"},{"id":"b06g","term":"New Product/Service Design and Development","def":"Operations work with marketing in relation to the design of a new product, using operations experience in production processes, warranty claims and materials.","key":"Process is led by marketing · Operations provide input on: how the product can be made · what materials can be used · how features can be made to work\n5 key stages: 1. Concept development (based on market research) · 2. Product design/prototype development · 3. Prototype testing and assessment · 4. Product refinement · 5. Production and product launch\nService providers consider: time, expertise, qualifications, experience, effort, customer service experience\nPos: reduction in wastage · increased speed in production · decreased warranty claims and increased customer satisfaction","group":"New Product/Service Design & Development"},{"id":"b06h","term":"Logistics","def":"Managing the distribution, transportation, storage and material handling and packaging of goods.","key":"Distribution: interdependence with marketing\nTransportation: must be time and cost efficient and appropriate for the product\nStorage: Warehousing (facilities for storage, protection and later distribution) · Distribution centres (short-term storage to reduce lead times for supplying stock to outlets — often for perishable items) · Both reduce wait times, prevent stock shortfalls, significant costs, location vital\nMaterial handling and packaging: some products require particular care when transported\nAutomated Warehouse Trucks (AWTs) can replace traditional forklifts and drivers","group":"Supply Chain Management"},{"id":"b06i","term":"E-Commerce (Supply Chain)","def":"The buying and selling of goods and services via the internet.","key":"E-procurement: electronic online order system to manage supply levels — when stock falls to a predetermined level, supplier automatically supplies a set quantity\nCan also sell products to consumers online (B2C)\nPos: quicker access to inputs · receive customer orders electronically → quicker fulfilment of customer orders","group":"Supply Chain Management"},{"id":"b06j","term":"Global Sourcing","key":"Global sourcing: accessing suppliers in different geographic locations around the world\nAdv: may be lower cost · greater volume · higher quality · access to unique inputs\nDisadv: unfavourable exchange rate movements · quality concerns · transportation/shipping delays","group":"Supply Chain Management"},{"id":"b06k","term":"Outsourcing","def":"The use of external providers to perform business activities, either onshore or offshore.","key":"Also known as Business Process Outsourcing (BPO)\nActivities that can be outsourced: manufacturing · logistics · distribution\nAdv: Increased process capability (access to better technologies and specialised labour) · Increased certainty of operational processes (SLAs require contractor meets pre-determined KPIs) · Increased speed · Cost savings (labour, regulations, economies of scale)\nDisadv: Ethical issues — loss of domestic jobs → impacts brand image · Quality control concerns · Loss of knowledge of business processes · Loss of control over standards","group":"Outsourcing"},{"id":"b06l","term":"Leading Edge Technology","def":"Technology that is the most advanced at a point in time.","key":"Includes 'bleeding edge technology': so new there is a level of uncertainty in using it\nExamples: AI · machine learning and design intelligence · remote manufacturing · robotic process automation\nAdv: long-term cost savings and efficiency · increased accuracy/precision (removal of human error) · fewer defects and decreased wastage · remove labour costs (capital–labour substitution)\nDisadv: high short-term cost (especially early technology) · may need to retrench workers → brand image issues · workforce retraining required","group":"Technology"},{"id":"b06m","term":"Established Technology","def":"Technology that is already widely adopted and used.","key":"Examples: PC · CAD and CAM · barcoding · robotics for assembly\nUnique adv: less expensive than leading edge\nUnique disadv: could be inferior to leading edge → lose competitive advantage\nAll other advantages and disadvantages same as leading edge","group":"Technology"},{"id":"b06n","term":"Inventory Management","key":"Inventory: the amount of raw materials, goods being processed and finished goods on hand\nObjective: balance holding enough stock to meet demand without holding too much (which ties up working capital)\nAdv of holding stock: avoid running out of stock, reduces risk of lost sales · can take advantage of bulk purchase discounts · buffer against supply chain disruptions\nDisadv of holding stock: cash tied up in inventory · storage costs · risk of obsolescence or spoilage","group":"Inventory Management"},{"id":"b06o","term":"LIFO (Last-In, First-Out)","def":"A method of inventory valuation where the most recently acquired items are assumed to be sold first.","key":"Example: a business receives new stock and sells it before the older stock\nIn times of rising prices → lower profit (higher COGS using recent, more expensive stock) → lower tax\nLess commonly used in Australia · Not permitted under AASB (Australian accounting standards)","group":"Inventory Management"},{"id":"b06p","term":"FIFO (First-In, First-Out)","def":"A method of inventory valuation where the oldest acquired items are assumed to be sold first.","key":"Example: first items received are the first to be sold or used\nIn times of rising prices → higher profit (lower COGS using older, cheaper stock)\nGenerally preferred by Australian businesses and accepted under AASB\nParticularly important for perishable goods (ensures oldest stock used first)","group":"Inventory Management"},{"id":"b06q","term":"JIT (Just-in-Time)","def":"An inventory management system where stock is received from suppliers only as it is needed in the production process.","key":"Adv: reduces storage costs · prevents money lying idle in inventory · reduces risk of obsolescence/spoilage · lean production\nDisadv: highly dependent on supplier reliability · if supplier fails to deliver → production halts → lost sales · requires strong supplier relationships and precise demand forecasting","group":"Inventory Management"},{"id":"b06r","term":"Quality Control","def":"The process of inspecting products or services to ensure they meet predetermined standards.","key":"Inspection-based approach · typically at the end of the production process\nAdv: prevents defective products reaching customers · identifies problems in production\nDisadv: does not prevent defects — only catches them after they occur · can be costly (inspection labour costs) · defective products still produced, wasting resources","group":"Quality Management"},{"id":"b06s","term":"Quality Assurance","def":"A planned and systematic approach to ensuring quality throughout the entire production process to prevent defects from occurring.","key":"System-based approach · focuses on preventing defects rather than detecting them\nInvolves: quality standards and procedures established at every stage of production · regular audits\nAdv: prevents defects from occurring → less wastage · more cost-effective than quality control in the long run\nDisadv: requires significant investment in systems, training and procedures","group":"Quality Management"},{"id":"b06t","term":"Quality Improvement","def":"The ongoing process of identifying and implementing changes to improve product quality and operational efficiency.","key":"Continuous improvement culture (Kaizen)\nStrategies: Six Sigma approach (define, measure, analyse, improve, control) · benchmarking · TQM (Total Quality Management)\nAdv: continuously improves product quality and efficiency · reduces defects and waste over time · enhances long-term competitive advantage\nNeg: requires ongoing investment in time and resources","group":"Quality Management"},{"id":"b06u","term":"Financial Costs (Resistance to Change)","key":"Significant upfront capital required to implement new operational processes, technology or strategies\nImplication: businesses may resist change if financial costs are seen as too high or ROI uncertain · need to assess long-term cost savings vs short-term costs","group":"Overcoming Resistance to Change"},{"id":"b06v","term":"Purchasing New Equipment","key":"New technology or machinery may require substantial capital investment\nMay also require redesigning the production process or facility layout\nResistance: high upfront cost · uncertainty about performance and reliability of new technology","group":"Overcoming Resistance to Change"},{"id":"b06w","term":"Redundancy Payments","key":"When new technology replaces labour (capital–labour substitution), workers may be retrenched\nBusiness must pay legally required redundancy payments to affected employees\nResistance: reluctance to bear the cost of redundancy payments · potential negative publicity and brand image damage","group":"Overcoming Resistance to Change"},{"id":"b06x","term":"Retraining","key":"New processes, technology or strategies require employees to be retrained\nRetraining takes time and is costly\nResistance: cost of retraining programs · time taken away from production · not all employees may successfully adapt to new skills","group":"Overcoming Resistance to Change"},{"id":"b06y","term":"Reorganising Plant Layout","key":"Changes to operations may require physical reorganisation of the plant or facility\nCan cause significant disruption to production during the transition period\nResistance: high cost of structural changes · production downtime during reorganisation","group":"Overcoming Resistance to Change"},{"id":"b06z","term":"Inertia (Resistance to Change)","key":"The tendency of people and organisations to resist change and maintain the status quo\nManagerial inertia: managers reluctant to change established processes they are comfortable with\nEmployee inertia: employees resistant to changes in work practices and routines\nStrategies to overcome: effective change management communication · employee involvement in change process · strong leadership","group":"Overcoming Resistance to Change"},{"id":"b070","term":"Global Sourcing (Global Factor)","key":"Accessing inputs from the most cost-effective sources around the world\nAdv: lower input costs · access to higher quality inputs not available domestically · access to unique inputs · greater volume\nDisadv: unfavourable exchange rate movements · quality concerns (lack of oversight) · transportation/shipping delays · ethical concerns about supplier practices","group":"Global Factors"},{"id":"b071","term":"Economies of Scale","def":"The cost advantages gained through increased production volume, resulting in a lower cost per unit.","key":"As production volume increases → fixed costs spread over more units → lower average cost per unit\nAchieved through: bulk purchasing discounts · more efficient use of machinery and labour · specialisation of workers\nGlobal context: global businesses can achieve economies of scale more easily due to access to larger markets\nPos: lower costs → higher profit margins OR lower prices → increased market share\nNeg: can only be achieved if sufficient demand exists","group":"Global Factors"},{"id":"b072","term":"Scanning and Learning","def":"Monitoring international business environments to identify and adopt innovative practices, technologies and ideas.","key":"Involves: researching how competitors in global markets operate · attending international trade shows and conferences · studying successful global businesses\nPos: allows businesses to adopt best-practice operations processes · can identify new technologies and production methods before competitors\nNeg: requires investment in time and resources · information gathered may not be directly applicable to the Australian business context","group":"Global Factors"},{"id":"b073","term":"Research and Development (Global Factor)","def":"Investment in creating new products, processes or technologies to maintain a competitive advantage in global markets.","key":"Global businesses invest in R&D to: develop innovative products · improve operational efficiency · stay ahead of international competitors\nPos: leads to new product development → new revenue streams · can result in more efficient production processes → lower costs\nNeg: expensive and time consuming · no guarantee of a successful outcome from R&D investment","group":"Global Factors"}]}]},"essay":{"id":"essay-demo","subjectId":"biz-hsc","title":"Operations strategies essay (sample)"},"chain":{"id":"chain-demo","subjectId":"biz-hsc","essayId":"essay-demo","title":"Paragraph 1 — outsourcing","created":null,"sentences":[{"id":"cs1","text":"Operations strategies such as outsourcing directly determine a business’s ability to achieve its cost leadership objectives.","kw":"outsourcing"},{"id":"cs2","text":"Qantas outsources heavy aircraft maintenance to specialised providers in Singapore and the Philippines, reducing maintenance costs by an estimated 30%.","kw":"Qantas"},{"id":"cs3","text":"This allows management to redirect capital toward fleet renewal, such as the Boeing 787 Dreamliner, which consumes 20% less fuel per passenger.","kw":"Dreamliner"},{"id":"cs4","text":"However, outsourcing exposes Qantas to quality-control risks and industrial disputes, as seen in the 2011 grounding of its entire fleet.","kw":"grounding"},{"id":"cs5","text":"To mitigate this, Qantas maintains rigorous supplier audits aligned with CASA safety standards.","kw":"audits"},{"id":"cs6","text":"Therefore, outsourcing demonstrates how effective operations strategies balance cost objectives against quality and reputational risk.","kw":"balance"}]}};
